update jst_user_coupon
set status = 'locked',
    order_id = #{orderId},
    update_by = #{updateBy},
    update_time = #{updateTime}
where user_coupon_id = #{userCouponId}
  and user_id = #{userId}
  and status = 'unused'
  and del_flag = '0'

update jst_user_coupon
