    use_time = #{updateTime},
    update_by = #{updateBy},
    update_time = #{updateTime}
where user_coupon_id = #{userCouponId}
  and order_id = #{orderId}
  and status = 'locked'
  and del_flag = '0'

update jst_user_coupon
